var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그대의 그런 종잡을 수 없는 판단은 저로 하여금 의문을 갖게 만듭니다.","JPN":"あなたのそのような不可思議な判断に、私は疑問を抱きます。","ENG":"I can't help but wonder about such an unpredictable decision of yours.","TWN":"你這令人摸不著頭緒的決定令我感到困惑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그러나 예언과 진리에 모호한 표현이 따르듯, 이 또한 그런 것이겠죠.","JPN":"しかし、預言と真理に曖昧な表現が伴うように、これもまたそのようなものなのでしょう。","ENG":"But perhaps this is just like prophesies and revelations, which sound vague at best.","TWN":"不過先知和預言也是有令人不明白的地方，感覺就跟現在一樣吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저를 섬기거나 제물을 베풀던 자들은 대개 부활과 영생에 눈이 멀어 있었습니다.","JPN":"私に仕え、供物を捧げていた者たちの多くは、復活と永生に目がくらんでいました。","ENG":"Most people who worshipped me and showered me with offerings were blinded by their desires for resurrection and immortality.","TWN":"以前想要服侍我或是把我當作祭物的人，通常都是執著於復活和永生的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그대는 언제나 올바른 눈을 가지고, 사리사욕을 위해 힘을 부리지 않죠.","JPN":"ですがあなたは常に正しい目を持ち、私利私欲のために力を使うこともしません。","ENG":"But you never deviate from justice or abuse your power for your selfish desires.","TWN":"但你的眼光總是透露出正直，而且不會為一己之私而玩弄權力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그대는 현명한 왕의 자질을 가지고 있습니다, 현자여.","JPN":"あなたは賢明な王の資質を持っています、賢者よ。","ENG":"Sage, You have the makings of a wise king.","TWN":"智者，你有成為明君的潛力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 내가 그대에게 품은 일말의 의심을 거둔다 하더라도, 난 그대를 섬길 수 없습니다,","JPN":"しかし、私があなたに抱いた一抹の疑いを晴らしたとしても、私はあなたに仕えることはできません。","ENG":"But even without the doubt I have about you, I can't serve you.","TWN":"但就算我收回對你的一絲懷疑，我還是無法服侍你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"서로가 나아가는 운명의 종점은 분명 한 곳을 가리키고 있으나……","JPN":"互いに進む運命の終点は、確かな場所を指していますが……","ENG":"Even though our paths point at the same destination of fate,","TWN":"因為我們的命運都會走到終點……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그곳에 우리가 함께 살아남는 결말 같은 것 따윈 없을 테니까요.","JPN":"そこに、我々がどちらも生き残る結末は存在しないでしょう。","ENG":"there's no way we'll get there together alive.","TWN":"而那個終點卻不是王子和公主過著幸福的生活。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 적어도 지금은, 당신을 해치고 싶지 않습니다.","JPN":"ですが少なくとも今は、あなたを傷つけたくありません。","ENG":"But I don't want to hurt you. At least not now.","TWN":"不過至少現在我沒有想害你的意思，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그대가 보다 현명한 선택을 통해, 우리와 같은 길을 따르게 될지는 알 수 없으니까요.","JPN":"あなたがより賢明な選択をすることで、我々と同じ道を歩むことになるかもしれませんので。","ENG":"There's still a possibility you might become wiser and follow our path.","TWN":"畢竟現在還無法確定，你是否會因為更聰明的選擇，而走上與我們相同的道路。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};